import sqlite3

def retrieve_order(user_id, order_id):
    conn = sqlite3.connect('my_database.db')  # connect to your SQLite database file (replace with actual filename)
    c = conn.cursor()
    
    query = f"SELECT * FROM orders WHERE user_id={user_id} AND order_id={order_id}" 
    c.execute(query)
    
    result = {}
    
    # Assuming the first row contains all relevant information about the order (change as necessary)
    for col_name, data in zip(c.description, c.fetchone()):  
        result[col_name[0]] = data 
        
    return result